formulas.expression:
/*  FROM EXCEL: =IF(RIGHT(Model,2)="S6", IF(OilSpec="Mineral",Parts!I117,Parts!I119),IF(OR(RIGHT(Model,2)="S7", RIGHT(Model,2)="S8"),IF(OilSpec="Mineral",Parts!I118,Parts!I120),IF(OilSpec="Mineral",Parts!I38,Parts!I39)))       */

IF(RIGHT({!Model},2)="S6", IF({!OilSpec_B18} = "Mineral", {!PartsI117}, {!PartsI119}), IF(OR(RIGHT({!Model},2)="S7",
RIGHT({!Model},2)="S8"), IF({!OilSpec_B18} = "Mineral", {!PartsI118}, {!PartsI120}), IF({!OilSpec_B18}  = "Mineral", {!PartsI38}, {!PartsI39})))
